  ('disabled-57f41407-moex-00306', 'disabled-57f41407', 'disabled-57f41407-moex-112-34c7f7f6', 'sub-disabled-57f41407-01', NULL, 'single_choice', '下列「」中詞語的使用，何者正確？', '["應當仔細聆聽法官「庭訓」，知錯能改，才能洗心革面", "幸虧有人製造笑料，「從中作梗」，才能緩解尷尬的氣氛", "獨學而無友，透過相互切磋，「同室操戈」，才能一同精進", "許多傳統技藝，因工作辛勞，面臨無人傳承「衣缽」的窘境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
